p.m:
\displaystyle{\begin{aligned}
   \left(-\frac{8}{5}\right) \div (-10)
       \amp = \frac{8}{5} \div 10 \\
       \amp = \frac{8}{5} \div \frac{10}{1} \\
       \amp = \frac{8}{5} \cdot \frac{1}{10} \amp \hbox{We can simplify by dividing 8 and 10 by 2, making the numbers smaller.}\\
       \amp = \frac{4}{5}\cdot \frac{1}{5} \\
       \amp = \frac{4 \cdot 1}{5 \cdot 5} \\
       \amp = \frac{4}{25}
\end{aligned}
    }
